package com.mccompanion.terminal;
import com.mccompanion.terminal.launcher.*;import java.nio.file.*;import java.util.*;import org.junit.jupiter.api.*;import org.junit.jupiter.api.io.TempDir;import static org.junit.jupiter.api.Assertions.*;
class HookServiceTest{@TempDir Path temp;MinecraftInstance instance(Path root)throws Exception{Path version=root.resolve(".minecraft/versions/Test");Files.createDirectories(version.resolve("PCL"));return new MinecraftInstance("id","launcher","Test",root.resolve(".minecraft"),version,version,version.resolve("mods"),version.resolve("config"),version.resolve("logs"),"1.21.1",LoaderType.FABRIC,"1",21,Optional.empty(),InstanceIsolation.VERSION_DIRECTORY,DetectionConfidence.HIGH);}LauncherInstallation launcher(Path root,LauncherType type)throws Exception{Path exe=root.resolve(type==LauncherType.PCL2?"PCL.exe":"HMCL.exe");Files.createDirectories(exe.getParent());Files.createFile(exe);Path data=type==LauncherType.PCL2?root.resolve("PCL"):root.resolve(".hmcl");Files.createDirectories(data);return new LauncherInstallation("launcher",type,"",exe,data,List.of(root.resolve(".minecraft")),DetectionConfidence.HIGH,Map.of());}
 @Test void pclSpecialExistingCommandIsIsolated()throws Exception{var i=instance(temp);var l=launcher(temp,LauncherType.PCL2);String command="echo 中文 & (echo x) ^| find \"x\"";Files.writeString(i.versionDirectory().resolve("PCL/Setup.ini"),"VersionAdvanceRun:"+command+"\n");Path home=temp.resolve("home");new HookService().install(i,l,temp.resolve("mcac.cmd"),home);Path state=home.resolve("hooks/id");assertTrue(Files.readString(state.resolve("pcl-prelaunch.cmd")).contains("user-existing-hook.cmd"));assertTrue(Files.readString(state.resolve("user-existing-hook.cmd")).contains(command));new HookService().remove(i,l,home);assertTrue(Files.readString(i.versionDirectory().resolve("PCL/Setup.ini")).contains(command));}
 @Test void hmclDuplicateSelectedVersionIsBlocked()throws Exception{var i=instance(temp);var l=launcher(temp,LauncherType.HMCL);Files.writeString(l.dataDirectory().resolve("hmcl.json"),"{\"configurations\":{\"a\":{\"selectedMinecraftVersion\":\"Test\"},\"b\":{\"selectedMinecraftVersion\":\"Test\"}}}");assertThrows(java.io.IOException.class,()->new HookService().install(i,l,temp.resolve("mcac.cmd"),temp.resolve("home")));}
}
